# Remove duplicate/placeholder entries
MOVIES = [m for m in MOVIES if m["overview"] and m["poster_url"]]


def seed():
    Base.metadata.create_all(bind=engine)
    db = SessionLocal()
    try:
        # Insert only movies not already in DB (idempotent by tmdb_id)
        added = 0
        for m in MOVIES:
            if not m["overview"] or not m["poster_url"]:
                continue
            if db.query(Movie).filter(Movie.tmdb_id == m["tmdb_id"]).first():
                continue
            db.add(Movie(
                tmdb_id=m["tmdb_id"],
                title=m["title"],
                overview=m["overview"],
                poster_url=m["poster_url"],
                backdrop_url=m.get("backdrop_url", ""),
                genres=m["genres"],
                cast=m["cast"],
                director=m["director"],
                release_year=m["release_year"],
                rating=m["rating"],
                vote_count=m["vote_count"],
                runtime=m["runtime"],
                language=m["language"],
                keywords=m["keywords"],
                popularity=m["popularity"],
            ))
            added += 1
        db.commit()
        print(f"Added {added} new movies (skipped existing)")

        # Admin user
        if not db.query(User).filter(User.email == "admin@cineai.com").first():
            db.add(User(
                username="admin",
                email="admin@cineai.com",
                hashed_password=hash_password("admin123"),
                is_admin=True,
                onboarding_complete=True,
            ))
            db.commit()
            print("Created admin user")

        # Demo user
        demo = db.query(User).filter(User.email == "demo@cineai.com").first()
        if not demo:
            demo = User(
                username="demo",
                email="demo@cineai.com",
                hashed_password=hash_password("demo123"),
                onboarding_complete=True,
                genre_preferences=["Action", "Science Fiction", "Thriller"],
            )
            db.add(demo)
            db.commit()
            db.refresh(demo)
            sample_ratings = [(1, 5), (2, 5), (3, 4.5), (4, 5), (7, 4), (9, 4.5), (32, 4.5), (33, 4)]
            for mid, rating_val in sample_ratings:
                db.add(Rating(user_id=demo.id, movie_id=mid, rating=rating_val))
            db.commit()
            print("Created demo user with sample ratings")

        # Retrain content model with all movies
        all_movies = db.query(Movie).all()
        movies_list = [
            {"id": m.id, "overview": m.overview, "genres": m.genres or [], "cast": m.cast or [],
             "director": m.director, "keywords": m.keywords or [], "rating": m.rating, "popularity": m.popularity}
            for m in all_movies
        ]
        print(f"Training content-based model on {len(movies_list)} movies...")
        content_recommender.fit(movies_list)
        print("Content model trained and saved")

    finally:
        db.close()


if __name__ == "__main__":
    seed()
